// =============================================================
// Compute Duration + Mark Paused
// =============================================================
// Calculates delay seconds, then marks step_execution=waiting
// and workflow_execution=paused via Promise.all().
// Eliminates fan-in race from 2 parallel Supabase UPDATEs.
// =============================================================

const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
if (!SUPABASE_URL) throw new Error('SUPABASE_URL environment variable not configured');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

// @inline supabase-request
async function supabaseRequest(path, method, body) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const match = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!match) { reject(new Error('Invalid SUPABASE_URL')); return; }
    const options = {
      hostname: match[1],
      path: match[2],
      method: method || 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation',
      },
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`Supabase ${method || 'GET'} ${path} ${res.statusCode}: ${data}`));
          return;
        }
        try {
          resolve(data ? JSON.parse(data) : null);
        } catch (e) {
          reject(new Error(`Parse error for ${path}: ${data}`));
        }
      });
    });
    req.on('error', reject);
    if (body !== undefined && body !== null) req.write(JSON.stringify(body));
    req.end();
  });
}
// @end-inline supabase-request

const item = $input.first().json;
const config = item.resolvedConfig || item.step.step_config;

const value = Number(config.value) || 1;
const unit = config.unit || 'minutes';
const multipliers = { minutes: 60, hours: 3600, days: 86400 };
const seconds = value * (multipliers[unit] || 60);

const resumeAt = new Date(Date.now() + seconds * 1000).toISOString();

// Mark step waiting + execution paused in parallel
await Promise.all([
  supabaseRequest(
    `workflow_step_executions?id=eq.${item.currentStepExecId}`,
    'PATCH',
    { status: 'waiting', resume_at: resumeAt }
  ),
  supabaseRequest(
    `workflow_executions?id=eq.${item.executionId}`,
    'PATCH',
    { status: 'paused' }
  ),
]);

return {
  json: {
    ...item,
    delaySeconds: seconds,
  }
};

